
const V103_KOREA_BASE = "data:image/png;base64,";

function v103MapShapeMarkup(activeProvinces=new Set(), compact=false){
  return mapProvinceShapes().map(([name,points])=>{
    const pts=points.split(" ");
    const cx=pts.reduce((s,p)=>s+Number(p.split(",")[0]),0)/pts.length;
    const cy=pts.reduce((s,p)=>s+Number(p.split(",")[1]),0)/pts.length;
    const active=activeProvinces.has(name);
    return `<polygon class="map-province ${active?"active":""}" points="${points}"/><text class="map-province-label" x="${cx}" y="${cy}">${name}</text>`;
  }).join("");
}

function v103IslandMarkup(activeAreas=new Set()){
  const defs=[
    {name:"강화",keys:["강화군"],cx:25.5,cy:27,rx:2.2,ry:1.7},
    {name:"울릉",keys:["울릉군","울릉도"],cx:94,cy:55,rx:1.25,ry:1.7},
    {name:"거제",keys:["거제시","거제도"],cx:72,cy:92,rx:1.8,ry:2.1},
    {name:"남해",keys:["남해군"],cx:58,cy:94,rx:1.6,ry:1.7},
    {name:"진도",keys:["진도군"],cx:20,cy:96,rx:1.6,ry:1.7},
    {name:"신안",keys:["신안군"],cx:14,cy:88,rx:2.2,ry:2.1},
    {name:"제주",keys:["제주특별자치도","제주시","서귀포시"],cx:38,cy:107,rx:9,ry:3.7}
  ];
  return defs.map(v=>{
    const active=v.keys.some(k=>activeAreas.has(normalizeText(k)));
    return `<ellipse class="map-island ${active?"active":""}" cx="${v.cx}" cy="${v.cy}" rx="${v.rx}" ry="${v.ry}"/><text class="map-island-label" x="${v.cx}" y="${v.cy+.6}">${v.name}</text>`;
  }).join("");
}

function mapMarkerMarkup(row,kind,selected=false,showLabel=true){
  const x=Number(row.x)||0, y=Number(row.y)||0;
  const label=String(row.name||"");
  const cls=kind==="store"?"store":(kind==="center"?"center":"tc");
  const attr=kind==="store"?`data-store="${esc(row.name)}"`:`data-tc="${esc(row.name)}"`;
  const width=Math.max(9,Math.min(25,label.length*3.2+5.5));
  const labelMarkup=showLabel?`<g class="map-marker-label"><rect x="2.6" y="-2.65" width="${width}" height="5.25" rx="1.8"/><text x="4.2" y=".75">${esc(label)}</text></g>`:"";
  return `<g class="map-marker ${cls} ${selected?"selected":""}" ${attr} transform="translate(${x} ${y})"><path class="pin" d="M0,-1.85 C-1.18,-1.85 -2,-1.02 -2,.03 C-2,1.35 0,3.3 0,3.3 C0,3.3 2,1.35 2,.03 C2,-1.02 1.18,-1.85 0,-1.85Z"/><circle class="pin-hole" cx="0" cy="-.15" r=".58"/>${labelMarkup}</g>`;
}

function v103ClusterMarkup(rows, kind){
  if(!rows.length) return "";
  const clusters=[];
  rows.forEach(row=>{
    const x=Number(row.x)||0,y=Number(row.y)||0;
    let c=clusters.find(v=>Math.hypot(v.x-x,v.y-y)<2.45);
    if(!c){c={x,y,rows:[]};clusters.push(c);}
    c.rows.push(row);
    c.x=c.rows.reduce((s,r)=>s+(Number(r.x)||0),0)/c.rows.length;
    c.y=c.rows.reduce((s,r)=>s+(Number(r.y)||0),0)/c.rows.length;
  });
  return clusters.map(c=>{
    if(c.rows.length===1)return mapMarkerMarkup(c.rows[0],kind,false,false);
    const color=kind==="store"?"#8b94a3":kind==="center"?"#2563eb":"#7c3aed";
    return `<g class="map-cluster" transform="translate(${c.x} ${c.y})"><circle r="1.45" fill="${color}"/><text x="0" y=".18">${c.rows.length}</text></g>`;
  }).join("");
}

function renderMapPanel(){
  if(!els.deptMapPanel)return;
  const md=getMapDataSafe();
  const tcRows=md.logistics.filter(r=>mapLogisticsKind(r)==="tc");
  if(els.mapStoreSelect){
    const current=mapSelectedStore;
    els.mapStoreSelect.innerHTML=`<option value="">코스트코 점포 선택</option>`+md.stores.slice().sort((a,b)=>processLocaleCompare(a.name,b.name)).map(r=>`<option value="${esc(r.name)}">${esc(r.name)}</option>`).join("");
    if(md.stores.some(r=>r.name===current))els.mapStoreSelect.value=current;
  }
  if(els.mapTcSelect){
    const current=mapSelectedTc;
    els.mapTcSelect.innerHTML=`<option value="">TC 선택</option>`+tcRows.slice().sort((a,b)=>processLocaleCompare(a.name,b.name)).map(r=>`<option value="${esc(r.name)}">${esc(r.name)}</option>`).join("");
    if(tcRows.some(r=>r.name===current))els.mapTcSelect.value=current;
  }
  const needStore=mapMode==="store";
  const needTc=mapMode==="coverage";
  if(els.mapSelectionBar)els.mapSelectionBar.classList.toggle("show",needStore||needTc);
  if(els.mapStoreSelectWrap)els.mapStoreSelectWrap.classList.toggle("show",needStore);
  if(els.mapTcSelectWrap)els.mapTcSelectWrap.classList.toggle("show",needTc);
  els.deptMapPanel.querySelectorAll(".map-mode-btn").forEach(btn=>btn.classList.toggle("active",btn.dataset.mapMode===mapMode));
  const detailOpen=mapMetroOpen&&Boolean(mapSelectedTc||mapSelectedStore);
  if(els.mapMetroToggle){
    els.mapMetroToggle.classList.toggle("show",Boolean(mapSelectedTc||mapSelectedStore));
    els.mapMetroToggle.textContent=detailOpen?"상세 닫기":"상세 확대 보기";
  }
  if(els.mapDetailLayout){
    els.mapDetailLayout.classList.toggle("detail-open",detailOpen);
    els.mapDetailLayout.classList.toggle("metro-open",detailOpen);
  }
  renderKoreaMap();renderMetroMap();renderMapInfo();renderMapCoverageList();
}

function renderKoreaMap(){
  if(!els.koreaMap)return;
  const md=getMapDataSafe();
  const selectedTc=md.logistics.find(r=>r.name===mapSelectedTc);
  const selectedStore=md.stores.find(r=>r.name===mapSelectedStore);
  const coverageRows=mapSelectedTc?md.coverage.filter(r=>r.tc===mapSelectedTc):[];
  const activeProvinces=new Set(coverageRows.map(r=>normalizeProvinceName(r.province)).filter(Boolean));
  const activeAreas=new Set(coverageRows.map(r=>normalizeText(r.area)));
  let stores=[],logistics=[];
  if(mapMode==="all"){stores=md.stores;logistics=md.logistics;}
  else if(mapMode==="store"){stores=mapSelectedStore?md.stores.filter(r=>r.name===mapSelectedStore):md.stores;if(selectedStore?.tc)logistics=md.logistics.filter(r=>r.name===selectedStore.tc);}
  else if(mapMode==="center"){logistics=md.logistics.filter(r=>mapLogisticsKind(r)==="center");}
  else if(mapMode==="tc"){logistics=md.logistics.filter(r=>mapLogisticsKind(r)==="tc");}
  else if(mapMode==="coverage"){logistics=mapSelectedTc?md.logistics.filter(r=>r.name===mapSelectedTc):md.logistics.filter(r=>mapLogisticsKind(r)==="tc");if(mapSelectedTc)stores=md.stores.filter(r=>r.tc===mapSelectedTc);}
  const connector=(selectedStore&&selectedTc)?`<path class="map-connection" d="M${Number(selectedStore.x)||0},${Number(selectedStore.y)||0} L${Number(selectedTc.x)||0},${Number(selectedTc.y)||0}"/>`:"";
  let storeMarks="",logisticsMarks="";
  if(mapMode==="all"){storeMarks=v103ClusterMarkup(stores,"store");logisticsMarks=v103ClusterMarkup(logistics.filter(r=>mapLogisticsKind(r)==="tc"),"tc")+v103ClusterMarkup(logistics.filter(r=>mapLogisticsKind(r)==="center"),"center");}
  else{storeMarks=stores.map(r=>mapMarkerMarkup(r,"store",mapSelectedStore===r.name,mapSelectedStore===r.name||mapMode==="store")).join("");logisticsMarks=logistics.map(r=>mapMarkerMarkup(r,mapLogisticsKind(r),mapSelectedTc===r.name,mapSelectedTc===r.name||mapMode!=="all")).join("");}
  const zoom=Math.max(1,Math.min(1.45,mapZoom||1));
  const vbW=100/zoom,vbH=118/zoom,vbX=(100-vbW)/2,vbY=(118-vbH)/2;
  const shapes=v103MapShapeMarkup(mapMode==="coverage"?activeProvinces:new Set());
  const islands=v103IslandMarkup(mapMode==="coverage"?activeAreas:new Set());
  els.koreaMap.innerHTML=`<svg class="korea-map-svg" viewBox="${vbX} ${vbY} ${vbW} ${vbH}" role="img" aria-label="전국 코스트코 및 물류 지도"><image href="${V103_KOREA_BASE}" x="0" y="0" width="100" height="118" preserveAspectRatio="xMidYMid meet"/><g>${shapes}${islands}</g>${connector}${storeMarks}${logisticsMarks}</svg>`;
  els.koreaMap.querySelectorAll("[data-store]").forEach(el=>el.addEventListener("click",()=>{mapSelectedStore=el.dataset.store||"";const st=md.stores.find(r=>r.name===mapSelectedStore);mapSelectedTc=st?.tc||"";mapMode="store";mapMetroOpen=true;renderMapPanel();setTimeout(()=>els.mapDetailLayout?.scrollIntoView({behavior:"smooth",block:"start"}),80);}));
  els.koreaMap.querySelectorAll("[data-tc]").forEach(el=>el.addEventListener("click",()=>{mapSelectedTc=el.dataset.tc||"";mapSelectedStore="";mapMode="coverage";mapMetroOpen=true;renderMapPanel();setTimeout(()=>els.mapDetailLayout?.scrollIntoView({behavior:"smooth",block:"start"}),80);}));
}

function v103DetailViewport(tc,rows,useMetro){
  if(useMetro)return {x:17,y:7,w:47,h:48};
  const cx=Number(tc?.x)||50,cy=Number(tc?.y)||55;
  const w=42,h=42;
  return {x:Math.max(0,Math.min(100-w,cx-w/2)),y:Math.max(0,Math.min(118-h,cy-h/2)),w,h};
}

function renderMetroMap(){
  if(!els.metroMap)return;
  const open=mapMetroOpen&&Boolean(mapSelectedTc||mapSelectedStore);
  els.metroMap.classList.toggle("show",open);
  if(!open){els.metroMap.innerHTML="";return;}
  const md=getMapDataSafe();
  const store=md.stores.find(r=>r.name===mapSelectedStore);
  const tcName=mapSelectedTc||(store?.tc||"");
  const tc=md.logistics.find(r=>r.name===tcName);
  const rows=tcName?md.coverage.filter(r=>r.tc===tcName).slice().sort((a,b)=>processLocaleCompare(a.area,b.area)):[];
  const metroRows=rows.filter(r=>["서울","경기","인천"].includes(normalizeProvinceName(r.province)));
  const useMetro=metroRows.length>0;
  const activeRows=useMetro?metroRows:rows;
  const activeProvinces=new Set(activeRows.map(r=>normalizeProvinceName(r.province)).filter(Boolean));
  const activeAreas=new Set(activeRows.map(r=>normalizeText(r.area)));
  const vp=v103DetailViewport(tc,activeRows,useMetro);
  const linked=tcName?md.stores.filter(s=>s.tc===tcName):[];
  const shapes=v103MapShapeMarkup(activeProvinces,true);
  const islands=v103IslandMarkup(activeAreas);
  const storeMarks=linked.map(s=>mapMarkerMarkup(s,"store",mapSelectedStore===s.name,true)).join("");
  const tcMark=tc?mapMarkerMarkup(tc,"tc",true,true):"";
  const title=useMetro?"수도권 확대 보기":`${tcName||"선택 거점"} 관할 권역 상세`;
  const chips=activeRows.length?activeRows.map(r=>`<span class="metro-area-chip">${esc(r.area)}</span>`).join(""):`<span class="map-select-hint">관할 권역이 아직 등록되지 않았습니다.</span>`;
  els.metroMap.innerHTML=`<div class="metro-map-head"><div class="metro-map-title">${esc(title)}</div><button class="metro-map-close" type="button" aria-label="상세 닫기">×</button></div><div class="metro-canvas"><svg class="metro-detail-svg" viewBox="${vp.x} ${vp.y} ${vp.w} ${vp.h}"><image class="metro-detail-bg" href="${V103_KOREA_BASE}" x="0" y="0" width="100" height="118" preserveAspectRatio="xMidYMid meet"/><g>${shapes}${islands}</g>${storeMarks}${tcMark}</svg></div><div class="metro-area-panel"><div class="metro-area-title">관할 시·군·구</div><div class="metro-area-chips">${chips}</div></div>`;
  const close=els.metroMap.querySelector(".metro-map-close");if(close)close.addEventListener("click",()=>{mapMetroOpen=false;renderMapPanel();});
}

function renderMapInfo(){
  if(!els.mapInfo)return;
  const md=getMapDataSafe();
  const store=md.stores.find(r=>r.name===mapSelectedStore);
  const tc=md.logistics.find(r=>r.name===mapSelectedTc);
  const row=store||tc;
  if(!row||!mapMetroOpen){els.mapInfo.innerHTML="";return;}
  const isStore=Boolean(store);
  const linked=isStore?[]:md.stores.filter(s=>s.tc===row.name).sort((a,b)=>processLocaleCompare(a.name,b.name));
  const coverage=isStore?[]:md.coverage.filter(r=>r.tc===row.name);
  const areaText=uniqueArray(coverage.map(r=>r.area).filter(Boolean)).join(", ");
  const linkedChips=!isStore&&linked.length?`<div class="map-linked-stores"><div class="map-linked-title">연결 점포</div><div class="map-linked-chips">${linked.map(s=>`<button class="map-linked-chip" type="button" data-linked-store="${esc(s.name)}">${esc(s.name)}</button>`).join("")}</div></div>`:"";
  els.mapInfo.innerHTML=`<div class="map-info-card"><div class="map-info-head"><div><div><span class="map-info-title">${esc(row.name)}</span><span class="map-info-selected">선택됨</span></div><div class="map-info-phone">☎ ${esc(row.phone||"미등록")}</div></div></div>${!isStore?`<div class="map-linked-count-box"><span>연결 점포</span><strong>${linked.length}개</strong></div><div class="map-overlay-section"><div class="map-overlay-label">관할 지역</div><div class="map-overlay-value">${esc(areaText||"시트 입력 전")}</div></div>`:`<div class="map-overlay-section"><div class="map-overlay-label">담당 물류</div><div class="map-overlay-value">${esc(row.tc||"미등록")}</div></div>`}<div class="map-overlay-section"><div class="map-overlay-label">주소</div><div class="map-overlay-value">${esc(row.address||"주소 입력 전")}</div></div>${linkedChips}<div class="map-actions"><button class="map-action copy" type="button" data-copy-address="${esc(row.address||"")}" ${row.address?"":"disabled"}>주소 복사</button></div></div>`;
  els.mapInfo.querySelectorAll("[data-copy-address]").forEach(btn=>btn.addEventListener("click",async()=>{try{await navigator.clipboard.writeText(btn.dataset.copyAddress||"");btn.textContent="복사 완료";setTimeout(()=>btn.textContent="주소 복사",1200)}catch(e){}}));
  els.mapInfo.querySelectorAll("[data-linked-store]").forEach(btn=>btn.addEventListener("click",()=>{mapSelectedStore=btn.dataset.linkedStore||"";const st=md.stores.find(r=>r.name===mapSelectedStore);mapSelectedTc=st?.tc||mapSelectedTc;mapMode="store";mapMetroOpen=true;renderMapPanel();}));
}

// 새 지도 모드 버튼 동작
if(els.deptMapPanel){
  const fresh=els.deptMapPanel.cloneNode(true);
  // 기존 이벤트는 유지해야 하므로 clone 교체하지 않음. 아래 캡처 단계 이벤트로 새 모드만 보완
  els.deptMapPanel.addEventListener("click",e=>{
    const btn=e.target.closest("[data-map-mode]");if(!btn)return;
    const next=btn.dataset.mapMode||"all";
    if(["center","tc"].includes(next)){mapMode=next;mapSelectedStore="";mapSelectedTc="";mapMetroOpen=false;mapZoom=1;renderMapPanel();}
  },true);
}
